  model(TSLM(Consumption ~ Income + Savings + Unemployment))

us_change_scenarios &lt;- scenarios(
  optimistic = new_data(us_change, 4) |&gt;
    mutate(Income = c(0.5, 0.8, 0.6, 1.0),
           Savings = c(0.1, -0.2, 0.1, -0.1),
